mapper.select:
SELECT c.id AS challengeId, c.title AS title, c.start_date AS startDate, c.end_date AS endDate, c.type AS type, c.target_count AS goalCount, c.target_amount AS goalAmount,
up.status AS myStatus, up.my_fee AS myDeposit, up.challenge_count AS actualCount, up.challenge_amount AS actualAmount,
COUNT(p.id) AS totalParticipants,
/* 종료면 SUCCESS, 진행중이면 NOT FAIL */ SUM( CASE WHEN c.end_date < CURDATE() AND p.status = 'SUCCESS' THEN 1 WHEN c.end_date >= CURDATE() AND p.status <> 'FAIL' THEN 1 ELSE 0 END ) AS survivorCount,
COALESCE(SUM(p.my_fee), 0) AS totalDeposit, COALESCE(SUM(CASE WHEN p.status = 'FAIL' THEN p.my_fee ELSE 0 END), 0) AS forfeitedDeposit,
CASE WHEN c.end_date < CURDATE() THEN 1 ELSE 0 END AS ended
FROM Challenge c /* 내 참여 레코드 (없으면 화면 자체가 의미 없으니 INNER JOIN) */ JOIN ChallengeParticipation up ON up.challenge_id = c.id AND up.user_id = #{userId}
/* 집계용 전체 참여자 */ JOIN ChallengeParticipation p ON p.challenge_id = c.id
WHERE c.id = #{challengeId} GROUP BY c.id, c.title, c.start_date, c.end_date, c.type, c.target_count, c.target_amount, up.status, up.my_fee, up.challenge_count, up.challenge_amount
